import sys

def solve() -> None:
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    t = data[0]
    idx = 1
    out_lines = []
    for _ in range(t):
        n = data[idx]
        idx += 1
        a = data[idx:idx + n]
        idx += n

        best = 0
        for i in range(n):
            cur = 1
            for j in range(n):
                if j == i:
                    cur *= a[j] + 1
                else:
                    cur *= a[j]
            if cur > best:
                best = cur
        out_lines.append(str(best))

    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

from typing import List

class Solution:
    def matrixSum(self, nums: List[List[int]]) -> int:
        # sort each row in decreasing order
        for row in nums:
            row.sort(reverse=True)

        # longest row determines number of rounds
        max_len = max(len(row) for row in nums)

        total = 0
        # simulate each round
        for k in range(max_len):
            cur_max = 0
            for row in nums:
                if len(row) > k:
                    # row[k] is the element removed from this row in round k
                    if row[k] > cur_max:
                        cur_max = row[k]
            total += cur_max

        return total

