class Solution:
    def maxArrayValue(self, nums: List[int]) -> int:
        # scan from right to left, building maximal mergable blocks
        cur = nums[-1]          # sum of current block
        ans = cur
        for i in range(len(nums) - 2, -1, -1):
            if nums[i] <= cur:
                cur += nums[i]          # merge into current block
            else:
                cur = nums[i]           # start a new block
            if cur > ans:
                ans = cur
        return ans

class Solution:
    def finalString(self, s: str) -> str:
        """
        Simulate typing on the faulty keyboard.
        """
        cur = []                     # current screen content as a list of chars
        for ch in s:
            if ch == 'i':
                cur.reverse()        # keyboard reverses the whole screen
