        max_val = n * n
        # frequency array, index 0 unused
        cnt = [0] * (max_val + 1)

        # count occurrences
        for row in grid:
            for val in row:
                cnt[val] += 1

        repeated = missing = -1
        for x in range(1, max_val + 1):
            if cnt[x] == 2:
                repeated = x
            elif cnt[x] == 0:
                missing = x

