class Solution:
    def minimumCost(self, source: str, target: str,
                    original: List[str], changed: List[str],
                    cost: List[int]) -> int:
        # 1. distance matrix for 26 letters
        dist = [[INF] * 26 for _ in range(26)]
        for i in range(26):
            dist[i][i] = 0

        # 2. direct edges (keep cheapest if multiple)
        for o, c, w in zip(original, changed, cost):
            u = ord(o) - 97
            v = ord(c) - 97
            if w < dist[u][v]:
                dist[u][v] = w

        # 3. Floyd‑Warshall
        for m in range(26):
            dm = dist[m]
            for i in range(26):
                di = dist[i]
                via = di[m]
                if via == INF:
                    continue
                for j in range(26):
                    nd = via + dm[j]
                    if nd < di[j]:
                        di[j] = nd

        # 4. compute answer
        total = 0
        for sc, tc in zip(source, target):
            u = ord(sc) - 97
            v = ord(tc) - 97
            d = dist[u][v]
            if d == INF:
                return -1
            total += d

        return total

