        # initialise extrema for p2
        max2 = -INF
        second_max2 = -INF
        cnt_max2 = 0
        min2 = INF
        second_min2 = INF
        cnt_min2 = 0

        # one pass to collect all needed information
        for v1, v2 in zip(p1, p2):
            # max1, second_max1, cnt_max1
            if v1 > max1:
                second_max1 = max1
                max1 = v1
                cnt_max1 = 1
            elif v1 == max1:
                cnt_max1 += 1
            elif v1 > second_max1:
                second_max1 = v1

            # min1, second_min1, cnt_min1
            if v1 < min1:
                second_min1 = min1
                min1 = v1
                cnt_min1 = 1
            elif v1 == min1:
