            elif v1 < second_min1:
                second_min1 = v1

            # max2, second_max2, cnt_max2
            if v2 > max2:
                second_max2 = max2
                max2 = v2
                cnt_max2 = 1
            elif v2 == max2:
                cnt_max2 += 1
            elif v2 > second_max2:
                second_max2 = v2

            # min2, second_min2, cnt_min2
            if v2 < min2:
                second_min2 = min2
                min2 = v2
                cnt_min2 = 1
            elif v2 == min2:
                cnt_min2 += 1
            elif v2 < second_min2:
                second_min2 = v2

        # if all values are equal, second_* stays at its initial value;
        # replace it by the same extreme so that the range stays zero
        if second_max1 == -INF:
            second_max1 = max1
        if second_min1 == INF:
            second_min1 = min1
        if second_max2 == -INF:
            second_max2 = max2
        if second_min2 == INF:
            second_min2 = min2

        answer = INF

        for i in range(n):
            # current extremes after removing point i
            if p1[i] == max1 and cnt_max1 == 1:
                cur_max1 = second_max1
            else:
                cur_max1 = max1

            if p1[i] == min1 and cnt_min1 == 1:
                cur_min1 = second_min1
            else:
                cur_min1 = min1

            if p2[i] == max2 and cnt_max2 == 1:
                cur_max2 = second_max2
            else:
                cur_max2 = max2

            if p2[i] == min2 and cnt_min2 == 1:
                cur_min2 = second_min2
            else:
                cur_min2 = min2

            candidate = max(cur_max1 - cur_min1, cur_max2 - cur_min2)
            if candidate < answer:
