class Solution:
    def medianOfUniquenessArray(self, nums: List[int]) -> int:
        n = len(nums)
        total = n * (n + 1) // 2
        k = (total + 1) // 2          # position of the lower median

        # ---------- helper: count subarrays with at most X distinct ----------
        def at_most(x: int) -> int:
            if x == 0:
                return 0
            freq = defaultdict(int)
            left = 0
            distinct = 0
            cnt = 0
            for right, val in enumerate(nums):
                if freq[val] == 0:
                    distinct += 1
                freq[val] += 1

                while distinct > x:
                    v = nums[left]
                    freq[v] -= 1
                    if freq[v] == 0:
                        distinct -= 1
                    left += 1

                cnt += right - left + 1
            return cnt

        # -------------------------- binary search ---------------------------
        low, high = 1, n          # answer is between 1 and n inclusive
        while low < high:
            mid = (low + high) // 2
            if at_most(mid) >= k:
                high = mid
            else:
                low = mid + 1
        return low

