import heapq

class Solution:
    def mostFrequentIDs(self, nums: List[int], freq: List[int]) -> List[int]:
        cnt = {}               # current count of each ID
        heap = []              # max-heap via negative counts
        ans = []

        for id_val, delta in zip(nums, freq):
            old = cnt.get(id_val, 0)
            new = old + delta          # never negative (guaranteed)

            if new == 0:
                # ID disappears from the collection
                if id_val in cnt:
                    del cnt[id_val]
            else:
                cnt[id_val] = new
                heapq.heappush(heap, (-new, id_val))

            # Remove stale entries from the top of the heap
            while heap:
                neg_c, iid = heap[0]
                # current count of iid (0 if absent)
                cur = cnt.get(iid, 0)
                if cur != -neg_c:
                    heapq.heappop(heap)   # stale, discard
                else:
                    break

            if not heap:
                ans.append(0)
            else:
                ans.append(-heap[0][0])

        return ans

