class Solution:
    def minimumSubstringsInPartition(self, s: str) -> int:
        n = len(s)
        # 1. prefix counters
        pref = [[0] * 26 for _ in range(n + 1)]
        for i, ch in enumerate(s):
            idx = ord(ch) - ord('a')
            for k in range(26):
                pref[i + 1][k] = pref[i][k] + (1 if k == idx else 0)

        # helper: is substring s[l:r] balanced ?
        def balanced(l: int, r: int) -> bool:
            need = -1
            for k in range(26):
                cnt = pref[r][k] - pref[l][k]
                if cnt == 0:
                    continue
                if need == -1:
                    need = cnt
                elif cnt != need:
                    return False
            return True   # at least one character existed (r>l)

        INF = n + 1
        dp = [INF] * (n + 1)
        dp[0] = 0

        # 2. DP over prefixes
        for i in range(1, n + 1):
            # try every possible previous cut
            for j in range(i):
                if balanced(j, i):
                    if dp[j] + 1 < dp[i]:
                        dp[i] = dp[j] + 1

        return dp[n]

