class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        N = zero + one                     # total length
        # dp0[z][c] – prefixes ending with c zeros
        # dp1[z][c] – prefixes ending with c ones
        dp0 = [[0] * (limit + 1) for _ in range(zero + 1)]
        dp1 = [[0] * (limit + 1) for _ in range(zero + 1)]

        # initialise length = 1
        if zero >= 1:
            dp0[1][1] = 1          # string "0"
        if one >= 1:
            dp1[0][1] = 1          # string "1"

        # iterate over current length
        for length in range(1, N):
            # tables for length+1
            nxt0 = [[0] * (limit + 1) for _ in range(zero + 1)]
            nxt1 = [[0] * (limit + 1) for _ in range(zero + 1)]

            max_z = min(zero, length)          # zeros that can appear so far
            for z in range(max_z + 1):
                o = length - z                 # ones used so far
                if o < 0 or o > one:
                    continue

                row0 = dp0[z]
                row1 = dp1[z]

                for c in range(1, limit + 1):
                    val0 = row0[c]
                    if val0:
                        # add a 0 (continue the zero run)
                        if z + 1 <= zero and c + 1 <= limit:
                            nxt0[z + 1][c + 1] = (nxt0[z + 1][c + 1] + val0) % MOD
                        # add a 1 (start a new one run)
                        if o + 1 <= one:
                            nxt1[z][1] = (nxt1[z][1] + val0) % MOD

                    val1 = row1[c]
                    if val1:
                        # add a 1 (continue the one run)
                        if o + 1 <= one and c + 1 <= limit:
                            nxt1[z][c + 1] = (nxt1[z][c + 1] + val1) % MOD
                        # add a 0 (start a new zero run)
                        if z + 1 <= zero:
                            nxt0[z + 1][1] = (nxt0[z + 1][1] + val1) % MOD

            dp0, dp1 = nxt0, nxt1

        # length N reached, collect answers
        ans = 0
        for c in range(1, limit + 1):
            ans = (ans + dp0[zero][c]) % MOD
            ans = (ans + dp1[zero][c]) % MOD
        return ans

