    S = data[0].strip()
    N = int(data[1].strip())
    L = len(S)

    # ----- easy case: N is large enough for any L‑bit number -----
    max_all = 0
    for ch in S:
        max_all = (max_all << 1) | (1 if ch != '0' else 0)   # '?' and '1' become 1
    if N >= (1 << L) - 1:
        # N is at least the largest L‑bit number, answer is the maximal possible
        print(max_all)
        return

    # ----- prepare bits of N (exactly L bits) -----
    Nbits = [(N >> (L - 1 - i)) & 1 for i in range(L)]

    from functools import lru_cache

    @lru_cache(maxsize=None)
    def possible(pos: int, tight: bool) -> bool:
        """Is there a completion from position pos onward respecting the tight flag?"""
        if pos == L:
            return True
        allowed = []
        ch = S[pos]
        if ch == '0':
            allowed = [0]
        elif ch == '1':
            allowed = [1]
        else:               # '?'
            allowed = [0, 1]

        for b in (1, 0):    # try larger bits first (order does not matter for existence)
            if b not in allowed:
                continue
            if not tight:
                nb = Nbits[pos]
                if b > nb:
                    continue
                new_tight = tight or (b < nb)
            else:
                new_tight = True
            if possible(pos + 1, new_tight):
                return True
        return False

    # If even the empty prefix cannot lead to a solution, answer is -1
    if not possible(0, False):
        print(-1)
        return

    # ----- construct the maximal number -----
    ans = 0
    tight = False
    for pos in range(L):
        allowed = []
        ch = S[pos]
        if ch == '0':
            allowed = [0]
        elif ch == '1':
            allowed = [1]
        else:
            allowed = [0, 1]

        chosen = None
        for b in (1, 0):
            if b not in allowed:
                continue
            if not tight:
                nb = Nbits[pos]
                if b > nb:
                    continue
                new_tight = tight or (b < nb)
            else:
                new_tight = True
            if possible(pos + 1, new_tight):
                chosen = b
                tight = new_tight
                break
        # chosen must exist because possible(0, False) is True
        ans = (ans << 1) | chosen

