import sys
from collections import deque

INF = 10 ** 9

def bfs(start_r, start_c, H, W, grid):
    """return 2‑D list of distances from (start_r,start_c)"""
    dist = [[-1] * W for _ in range(H)]
    q = deque()
    q.append((start_r, start_c))
    dist[start_r][start_c] = 0
    while q:
        r, c = q.popleft()
        d = dist[r][c] + 1
        nr = r - 1
        if nr >= 0 and grid[nr][c] != '#' and dist[nr][c] == -1:
            dist[nr][c] = d
            q.append((nr, c))
        nr = r + 1
        if nr < H and grid[nr][c] != '#' and dist[nr][c] == -1:
            dist[nr][c] = d
            q.append((nr, c))
        nc = c - 1
        if nc >= 0 and grid[r][nc] != '#' and dist[r][nc] == -1:
            dist[r][nc] = d
            q.append((r, nc))
        nc = c + 1
        if nc < W and grid[r][nc] != '#' and dist[r][nc] == -1:
            dist[r][nc] = d
            q.append((r, nc))
    return dist

def solve() -> None:
    it = iter(sys.stdin.read().splitlines())
    H, W, T = map(int, next(it).split())
    grid = [list(next(it).rstrip()) for _ in range(H)]

    candies = []
    sr = sc = gr = gc = -1
    for i in range(H):
        for j in range(W):
            ch = grid[i][j]
            if ch == 'S':
                sr, sc = i, j
            elif ch == 'G':
                gr, gc = i, j
            elif ch == 'o':
                candies.append((i, j))

    C = len(candies)                     # ≤ 18
    N = C + 2                            # candies + S + G
    points = candies + [(sr, sc), (gr, gc)]

    # distance matrix
    dist = [[INF] * N for _ in range(N)]

    for idx, (r, c) in enumerate(points):
        dgrid = bfs(r, c, H, W, grid)
        for jdx, (rr, cc) in enumerate(points):
            d = dgrid[rr][cc]
            if d != -1:
                dist[idx][jdx] = d

    # indices
    S_idx = C
    G_idx = C + 1

    # DP over subsets of candies
    size = 1 << C
    dp = [[INF] * C for _ in range(size)]

    # initialise with first candy
    for c in range(C):
        d = dist[S_idx][c]
        if d < INF:
            dp[1 << c][c] = d

    # iterate masks
    for mask in range(size):
        # skip empty mask (already handled)
        if mask == 0:
            continue
        for last in range(C):
            if not (mask & (1 << last)):
                continue
            cur = dp[mask][last]
            if cur >= INF:
                continue
            # try to go to a new candy
            for nxt in range(C):
                if mask & (1 << nxt):
                    continue
                nd = dist[last][nxt]
                if nd >= INF:
                    continue
                nmask = mask | (1 << nxt)
                newlen = cur + nd
                if newlen < dp[nmask][nxt]:
                    dp[nmask][nxt] = newlen

    # answer
    ans = -1
    # case without any candy
    if dist[S_idx][G_idx] <= T:
        ans = 0

    # masks with candies
    for mask in range(1, size):
        pc = mask.bit_count()
        for last in range(C):
            if not (mask & (1 << last)):
                continue
            cur = dp[mask][last]
            if cur >= INF:
                continue
            total = cur + dist[last][G_idx]
            if total <= T:
                if pc > ans:
                    ans = pc

    print(ans)

