import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    M = int(next(it))
    strings = [next(it) for _ in range(N)]

    # adjacency: edge if Hamming distance == 1
    adj = [[False] * N for _ in range(N)]

    def hamming(a: str, b: str) -> int:
        diff = 0
        for i in range(M):
            if a[i] != b[i]:
                diff += 1
                if diff > 1:
                    break
        return diff

    for i in range(N):
        for j in range(i + 1, N):
            if hamming(strings[i], strings[j]) == 1:
                adj[i][j] = adj[j][i] = True

    full_mask = (1 << N) - 1
    # dp[mask][last] as a list of bitsets (or bool matrix)
    dp = [ [False] * N for _ in range(1 << N) ]

    for i in range(N):
        dp[1 << i][i] = True

    for mask in range(1 << N):
        # iterate over possible last vertices
        for last in range(N):
            if not dp[mask][last]:
                continue
            # try to extend the path
            for nxt in range(N):
                if mask >> nxt & 1:
                    continue
                if adj[last][nxt]:
                    dp[mask | (1 << nxt)][nxt] = True

    # check any ending vertex for full mask
    answer = any(dp[full_mask][last] for last in range(N))
    print("Yes" if answer else "No")

