def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]
    S = next(it).strip()

    # suffix counts of X for each value 0,1,2
    suffixX = [[0] * (N + 1) for _ in range(3)]
    for i in range(N - 1, -1, -1):
        for v in range(3):
            suffixX[v][i] = suffixX[v][i + 1]
        if S[i] == 'X':
            suffixX[A[i]][i] += 1

    prefM = [0, 0, 0]          # counts of M before current index, per value
    ans = 0

    # helper: mex of three numbers 0..2
    def mex3(x, y, z):
        mask = (1 << x) | (1 << y) | (1 << z)
        if mask & 1 == 0:
            return 0
        if mask & 2 == 0:
            return 1
        if mask & 4 == 0:
            return 2
        return 3

    for j in range(N):
        if S[j] == 'E':
            aj = A[j]
            # counts of X after j are stored at position j+1
            for v1 in range(3):
                cntM = prefM[v1]
                if cntM == 0:
                    continue
                for v3 in range(3):
                    cntX = suffixX[v3][j + 1]
                    if cntX == 0:
                        continue
                    ans += cntM * cntX * mex3(v1, aj, v3)

        if S[j] == 'M':
            prefM[A[j]] += 1

    print(ans)


