from collections import deque

def solve() -> None:
    it = iter(sys.stdin.read().split())
    H = int(next(it))
    W = int(next(it))
    grid = [list(next(it).strip()) for _ in range(H)]

    # alive[i][j] == 1  <=> cookie still present
    alive = [bytearray(b'\x01' * W) for _ in range(H)]

    # counters
    row_tot = [W] * H
    col_tot = [H] * W

    row_cnt = [[0] * 26 for _ in range(H)]
    col_cnt = [[0] * 26 for _ in range(W)]

    for i in range(H):
        for j, ch in enumerate(grid[i]):
            c = ord(ch) - 97
            row_cnt[i][c] += 1
            col_cnt[j][c] += 1

    # helpers -------------------------------------------------
    def uniform_row(i):
        if row_tot[i] < 2:
            return -1
        for c in range(26):
            if row_cnt[i][c] == row_tot[i]:
                return c
        return -1

    def uniform_col(j):
        if col_tot[j] < 2:
            return -1
        for c in range(26):
            if col_cnt[j][c] == col_tot[j]:
                return c
        return -1
    # ---------------------------------------------------------

    q = deque()
    for i in range(H):
        col = uniform_row(i)
        if col != -1:
            q.append(('r', i))
    for j in range(W):
        col = uniform_col(j)
        if col != -1:
            q.append(('c', j))

    while q:
        typ, idx = q.popleft()
        if typ == 'r':
            col = uniform_row(idx)
            if col == -1:
                continue
            # delete whole row idx
            for j in range(W):
                if alive[idx][j]:
                    alive[idx][j] = 0
                    row_tot[idx] -= 1
                    row_cnt[idx][col] -= 1

                    col_tot[j] -= 1
                    col_cnt[j][col] -= 1

                    # maybe column j became uniform
                    if col_tot[j] >= 2:
                        for cc in range(26):
                            if col_cnt[j][cc] == col_tot[j]:
                                q.append(('c', j))
                                break
        else:   # column
            col = uniform_col(idx)
            if col == -1:
                continue
            for i in range(H):
                if alive[i][idx]:
                    alive[i][idx] = 0
                    col_tot[idx] -= 1
                    col_cnt[idx][col] -= 1

                    row_tot[i] -= 1
                    row_cnt[i][col] -= 1

                    # maybe row i became uniform
                    if row_tot[i] >= 2:
                        for rc in range(26):
                            if row_cnt[i][rc] == row_tot[i]:
                                q.append(('r', i))
                                break

    # answer = total remaining cookies
    ans = sum(row_tot)
    print(ans)


