import sys

def ok(s: str, t: str) -> bool:
    ls, lt = len(s), len(t)
    if abs(ls - lt) > 1:
        return False

    if ls == lt:                     # possible substitution / equality
        diff = 0
        for a, b in zip(s, t):
            if a != b:
                diff += 1
                if diff > 1:
                    return False
        return True                  # 0 or 1 mismatches

    if ls + 1 == lt:                 # t is longer -> one insertion into s
        i = j = 0
        skipped = False
        while i < ls and j < lt:
            if s[i] == t[j]:
                i += 1
                j += 1
            else:
                if skipped:
                    return False
                skipped = True
                j += 1               # skip the extra character of t
        # possible extra character at the very end is also allowed
        return True

    # ls == lt + 1  -> s is longer -> one deletion from s
    i = j = 0
    skipped = False
    while i < ls and j < lt:
        if s[i] == t[j]:
            i += 1
            j += 1
        else:
            if skipped:
                return False
            skipped = True
            i += 1                   # skip the extra character of s
    return True

