def solve() -> None:
    input = sys.stdin.readline

    N = int(input())
    D = list(map(int, input().split()))
    L1, C1, K1 = map(int, input().split())
    L2, C2, K2 = map(int, input().split())

    # use the sensor type with the smaller capacity as the DP dimension
    if K1 > K2:
        L1, L2 = L2, L1
        C1, C2 = C2, C1
        K1, K2 = K2, K1

    INF = 10 ** 9          # larger than any possible number of type‑2 sensors
    dp = [INF] * (K1 + 1)
    dp[0] = 0

    for d in D:
        # maximal useful number of type‑1 sensors for this section
        t_max = min(K1, (d + L1 - 1) // L1)

        # pre‑compute needed type‑2 sensors for every t
        need2 = [0] * (t_max + 1)
        for t in range(t_max + 1):
            rem = d - t * L1
            if rem <= 0:
                need2[t] = 0
            else:
                need2[t] = (rem + L2 - 1) // L2

        new_dp = [INF] * (K1 + 1)
        for used in range(K1 + 1):
            cur = dp[used]
            if cur == INF:
                continue
            max_add = K1 - used
            limit = t_max if t_max <= max_add else max_add
            for t in range(limit + 1):
                nxt = used + t
                val = cur + need2[t]
                if val < new_dp[nxt]:
                    new_dp[nxt] = val
        dp = new_dp

    answer = None
    for x in range(K1 + 1):
        y = dp[x]          # minimal type‑2 sensors when x type‑1 sensors are used
        if y <= K2:
            cost = x * C1 + y * C2
            if answer is None or cost < answer:
                answer = cost

    if answer is None:
        print(-1)
    else:
        print(answer)


