def inversions(perm):
    """number of inversions of a permutation given as a list"""
    inv = 0
    n = len(perm)
    for i in range(n):
        pi = perm[i]
        for j in range(i + 1, n):
            if pi > perm[j]:
                inv += 1
    return inv

