import sys

class BIT:
    """Fenwick Tree for point updates and prefix sums."""
    def __init__(self, n):
        self.n = n
        self.bit = [0] * (n + 1)

    def add(self, idx, delta):
        while idx <= self.n:
            self.bit[idx] += delta
            idx += idx & -idx

    def prefix_sum(self, idx):
        s = 0
        while idx:
            s += self.bit[idx]
            idx -= idx & -idx
        return s

    def range_sum(self, l, r):
        if l > r:
            return 0
        return self.prefix_sum(r) - self.prefix_sum(l - 1)


