import sys
from functools import lru_cache

def solve() -> None:
    data = list(map(int, sys.stdin.read().strip().split()))
    if len(data) != 9:
        return
    A = data                     # values of the 9 cells, index 0..8

    # masks of the eight winning lines
    LINES = [
        0b000000111, 0b000111000, 0b111000000,   # rows
        0b001001001, 0b010010010, 0b100100100,   # columns
        0b100010001, 0b001010100                # diagonals
    ]

    @lru_cache(maxsize=None)
    def has_line(mask: int) -> bool:
        for line in LINES:
            if (mask & line) == line:
                return True
        return False

    @lru_cache(maxsize=None)
    def score(mask: int) -> int:
        s = 0
        i = 0
        m = mask
        while m:
            if m & 1:
                s += A[i]
            m >>= 1
            i += 1
        return s

    FULL = (1 << 9) - 1

    @lru_cache(maxsize=None)
    def win(red: int, blue: int, turn: int) -> bool:
        """True  ⇔ Takahashi can force a win from this position."""
        # already finished ?
        if has_line(red):
            return True          # Takahashi already has a line
        if has_line(blue):
            return False         # Aoki already has a line

        white = FULL ^ (red | blue)
        if white == 0:           # board full, decide by scores
            return score(red) > score(blue)

        # iterate over white cells
        if turn == 0:            # Takahashi's move
            w = white
            while w:
                lsb = w & -w
                i = (lsb.bit_length() - 1)
                new_red = red | lsb
                # immediate win ?
                if has_line(new_red):
                    return True
                if win(new_red, blue, 1):
                    return True
                w -= lsb
            return False         # no winning move
        else:                    # Aoki's move
            w = white
            while w:
                lsb = w & -w
                i = (lsb.bit_length() - 1)
                new_blue = blue | lsb
                # immediate win for Aoki → Takahashi loses
                if has_line(new_blue):
                    return False
                if not win(red, new_blue, 0):
                    return False
                w -= lsb
            return True          # every move lets Takahashi win

    result = win(0, 0, 0)
    print("Takahashi" if result else "Aoki")

