import sys
from collections import deque

def solve() -> None:
    data = sys.stdin.read().splitlines()
    if not data:
        return
    H, W = map(int, data[0].split())
    grid = data[1:]

    # magnet[i][j] == True  <=>  cell contains '#'
    magnet = [[c == '#' for c in row] for row in grid]

    # free[i][j] == True  <=>  '.' and no adjacent magnet
    free = [[False] * W for _ in range(H)]

    # directions
    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    for i in range(H):
        for j in range(W):
            if magnet[i][j]:
                continue
            ok = True
            for di, dj in dirs:
                ni, nj = i + di, j + dj
                if 0 <= ni < H and 0 <= nj < W and magnet[ni][nj]:
                    ok = False
                    break
            free[i][j] = ok

    visited = [[False] * W for _ in range(H)]
    ans = 1          # at least one blocked cell exists (problem guarantee)

    for i in range(H):
        for j in range(W):
            if not free[i][j] or visited[i][j]:
                continue
            # start BFS for this free component
            q = deque()
            q.append((i, j))
            visited[i][j] = True
            cnt_free = 0
            blocked_neighbours = set()

            while q:
                x, y = q.popleft()
                cnt_free += 1
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if not (0 <= nx < H and 0 <= ny < W):
                        continue
                    if magnet[nx][ny]:
                        continue          # cannot step onto a magnet
                    if free[nx][ny]:
                        if not visited[nx][ny]:
                            visited[nx][ny] = True
                            q.append((nx, ny))
                    else:
                        # blocked cell ('.' with at least one adjacent magnet)
                        blocked_neighbours.add(nx * W + ny)

            component_size = cnt_free + len(blocked_neighbours)
            if component_size > ans:
                ans = component_size

    print(ans)


if __name__ == "__main__":
    solve()

